<template>
  <v-form
    ref="form"
    v-model="valid"
    class="profile ma-3"
    lazy-validation
  >
    <h3 align="center">{{ $t ('contest.add') }}</h3>
    <v-text-field
      v-model="form.name"
      :counter="100"
      :rules="nameRules"
      :label="$t ('contest_name')"
      required
    ></v-text-field>

    <v-text-field
      v-model="form.english_name"
      :counter="100"
      :label="$t ('contest_english_name')"
    ></v-text-field>

    <v-text-field
      v-model="form.organizer"
      :counter="100"
      :rules="nameRules"
      :label="$t ('organizer')"
      required
    ></v-text-field>

    <v-text-field
      v-model="form.english_organizer"
      :counter="100"
      :label="$t ('english_organizer')"
    ></v-text-field>

    <v-text-field
      v-model="form.location"
      :counter="100"
      :rules="nameRules"
      :label="$t ('location')"
      required
    ></v-text-field>

    <v-text-field
      v-model="form.english_location"
      :counter="100"
      :label="$t ('english_location')"
    ></v-text-field>

    <v-text-field
      v-model="form.region"
      :counter="100"
      :rules="nameRules"
      :label="$t ('region')"
