      :rules="urlRules"
      :label="$t ('link')"
      required
    ></v-text-field>

    <v-datetime-picker
      :label="$t ('start_at')"
      locale="zh-tw"
      v-model="form.start_at">
    </v-datetime-picker>

    <v-datetime-picker
      :label="$t ('sign_start_at')"
      locale="zh-tw"
      v-model="form.sign_start_at">
    </v-datetime-picker>

    <v-datetime-picker
      :label="$t ('sign_end_at')"
      locale="zh-tw"
      v-model="form.sign_end_at">
    </v-datetime-picker>

    <v-checkbox
      v-model="form.iaaf"
      :label="$t ('iaaf')"
    ></v-checkbox>

    <v-checkbox
      v-model="form.aims"
      :label="$t ('aims')"
    ></v-checkbox>
    
    <v-checkbox
      v-model="form.measured"
      :label="$t ('measured')"
    ></v-checkbox>

    <v-checkbox
      v-model="form.recordable"
      :label="$t ('recordable')"
    ></v-checkbox>

    <v-btn
      block
      dark
      :disabled="!valid"
      color="teal darken-1"
      @click="validate"
    >
      {{ $t ('submit') }}
    </v-btn>

    <v-btn
      block
      dark
      color="error"
      @click="reset"
    >
      {{ $t ('reset_form') }}
    </v-btn>
  </v-form>

</template>

<script>
export default {
  name: 'EventsCreate',
  data () {
    return {
      valid: false,
      form: {
        name: '',
        english_name: '',
        organizer: '',
        english_organizer: '',
        location: '',
        english_location: '',
        level: '',
        region: '',
        url: '',
        start_at: null,
        sign_start_at: null,
        sign_end_at: null,
        iaaf: false,
        aims: false,
        measured: false,
        recordable: false,
      },
      nameRules: [
        v => !!v || 'Name is required',
        v => (v && v.length <= 100) || 'Name must be less than 100 characters'
      ],
      urlRules: [
        v => !!v || 'Url is required',
        v => (v && v.length <= 200) || 'Url must be less than 100 characters'
      ],
    }
  },
  mounted () {
    if ( ! this.hasPermission (true)) {
      this.$router.replace ({ name: 'event_index', })
    }
  },
  methods: {
    submit () {
      let submitForm = {}
      Object.assign (submitForm, this.form)

      submitForm.start_at = this.convertDate (submitForm.start_at)
      submitForm.sign_start_at = this.convertDate (submitForm.sign_start_at)
      submitForm.sign_end_at = this.convertDate (submitForm.sign_end_at)
      //TODO: Add distance handling
      submitForm.distance = []
      this.runnersPlaza.postEvent(submitForm).then ((event) => {
        if (event.id != undefined) {
          this.$router.replace ({ name: 'events/' + id + '/update', })
        }
      })
    },
    validate () {
      if (this.$refs.form.validate()) {
	this.submit()
      }
    },
    reset () {
      if (confirm(this.$t('confirm.reset_form'))) {
        this.$refs.form.reset()
      }
    },
    resetValidation () {
      this.$refs.form.resetValidation()
    }
  },
}
</script>

